import{_ as s,C as r,o as l,c as h,a2 as o,G as i,j as n,a}from"./chunks/framework.xf7WxEUW.js";const p="/Python-Programming/assets/lab-1-1.BE7wWrMs.png",c="/Python-Programming/assets/lab-1-2.JptJRb1z.png",d="/Python-Programming/assets/lab-1-3.CH8K3W-c.png",g="/Python-Programming/assets/lab-1-4.DRPaynzS.png",u="/Python-Programming/assets/lab-1-5.CnH0tsdd.png",y="/Python-Programming/assets/lab-1-6.fsAWm9Cd.png",m="/Python-Programming/assets/lab-1-7.BW2nIa4m.png",S=JSON.parse('{"title":"Lab 1 - Tool Orientation (VS Code and GitHub)","description":"","frontmatter":{"outline":"deep","title":"Lab 1 - Tool Orientation (VS Code and GitHub)"},"headers":[],"relativePath":"labs/lab-01.md","filePath":"labs/lab-01.md"}'),k={name:"labs/lab-01.md"},b={id:"cloning-using-the-terminal",tabindex:"-1"};function f(w,e,C,F,v,_){const t=r("Badge");return l(),h("div",null,[e[3]||(e[3]=o('<h1 id="lab-01-tool-orientation-vs-code-and-github" tabindex="-1">Lab 01 : Tool Orientation (VS Code and GitHub) <a class="header-anchor" href="#lab-01-tool-orientation-vs-code-and-github" aria-label="Permalink to &quot;Lab 01 : Tool Orientation (VS Code and GitHub)&quot;">​</a></h1><p>This lab walks you through setting up <strong>Git</strong> and <strong>VS Code</strong>, then using their graphical interfaces to manage the <code>class-cp115-repo</code> on <strong>GitHub</strong>.</p><h2 id="install-git-and-vs-code" tabindex="-1">Install Git and VS Code <a class="header-anchor" href="#install-git-and-vs-code" aria-label="Permalink to &quot;Install Git and VS Code&quot;">​</a></h2><ul><li>Follow the <a href="/Python-Programming/labs/installation.html#git"><strong>Git</strong> installation guide</a> for details on downloading and configuring <strong>Git</strong>.</li><li>Follow the <a href="/Python-Programming/labs/installation.html#vs-code"><strong>VS Code</strong> installation guide</a> to install the editor.</li><li>In <strong>VS Code</strong>, open the <code>Extensions</code> panel and install the <strong>Python</strong> extension from <strong>Microsoft</strong>.</li></ul><br><p align="center"><img src="'+p+'" alt="drawing" width="400"></p><h2 id="create-a-github-account" tabindex="-1">Create a GitHub Account <a class="header-anchor" href="#create-a-github-account" aria-label="Permalink to &quot;Create a GitHub Account&quot;">​</a></h2><p><strong>GitHub</strong> is the online platform where we store and share all the code for this course. Before you can fork, clone, or push any code, you need your own free <strong>GitHub</strong> account.</p>',8)),i(t,{type:"tip",text:"Task"}),e[4]||(e[4]=o('<ol><li>Open your browser and go to <a href="https://github.com/signup" target="_blank" rel="noreferrer">https://github.com/signup</a>.</li><li>Enter your <strong>email address</strong>. Use an email you check regularly so you can verify your account.</li><li>Create a strong <strong>password</strong> and choose a <strong>username</strong>. This username is how others will see you on <strong>GitHub</strong>, so pick something clear and professional.</li></ol><p>Once your account is created and verified, you are ready to continue.</p><h2 id="preparing-your-workspace-folder" tabindex="-1">Preparing Your Workspace Folder <a class="header-anchor" href="#preparing-your-workspace-folder" aria-label="Permalink to &quot;Preparing Your Workspace Folder&quot;">​</a></h2><p>Before working with <strong>GitHub</strong>, you need a place on your computer to keep your work. Keeping everything in one organized folder makes your files easy to find later.</p>',4)),i(t,{type:"tip",text:"Task"}),e[5]||(e[5]=o(`<p>First, create a folder named after yourself on your <strong>Desktop</strong>:</p><ol><li>Go to your <strong>Desktop</strong>.</li><li>Right-click on an empty area and choose <code>New</code> → <code>Folder</code>.</li><li>Name the folder using your own name, for example <code>aiman-cp115</code>.</li></ol><br><p>Now open that folder in <strong>VS Code</strong> so it becomes your working area:</p><ol><li>Open <strong>VS Code</strong>.</li><li>From the top menu, click <code>File</code> → <code>Open Folder...</code>.</li><li>Browse to your <strong>Desktop</strong>, select the folder you just created, and click <code>Select Folder</code>.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also open the folder directly by right-clicking it on the <strong>Desktop</strong> and choosing <code>Open with Code</code>.</p></div><p>Once the folder is open, you will see its name at the top of the <strong>Explorer</strong> panel on the left side of <strong>VS Code</strong>. This is where your cloned repository will live.</p><h2 id="install-github-cli" tabindex="-1">Install GitHub CLI <a class="header-anchor" href="#install-github-cli" aria-label="Permalink to &quot;Install GitHub CLI&quot;">​</a></h2><p><strong>GitHub CLI</strong> (<code>gh</code>) is a command-line tool that brings <strong>GitHub</strong> directly into your terminal. In this course, we use it to authenticate your machine with <strong>GitHub</strong> so that pushing and pulling code works without entering your credentials every time.</p><p>In <strong>VS Code</strong>, open a terminal by clicking <code>Terminal</code> in the top menu bar, then selecting <code>New Terminal</code>. A terminal panel will appear at the bottom of <strong>VS Code</strong>.</p><p>Install <strong>GitHub CLI</strong> using <code>winget</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">winget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GitHub.cli</span></span></code></pre></div><p>Once installed, close and reopen the terminal, then verify:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>You should see a version number printed.</p><h3 id="logging-in" tabindex="-1">Logging In <a class="header-anchor" href="#logging-in" aria-label="Permalink to &quot;Logging In&quot;">​</a></h3><p>Run the following command to authenticate with <strong>GitHub</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre></div><p>Follow the prompts:</p><ul><li>Select <strong>GitHub.com</strong></li><li>Select <strong>HTTPS</strong></li><li>When asked to authenticate, choose <strong>Login with a web browser</strong></li><li>A one-time code will appear in the terminal — copy it, press <kbd>Enter</kbd> to open the browser, paste the code, and authorise the app</li></ul><p>Once done, verify you are logged in:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>You should see your <strong>GitHub</strong> username confirmed.</p><h3 id="setting-up-your-identity" tabindex="-1">Setting Up Your Identity <a class="header-anchor" href="#setting-up-your-identity" aria-label="Permalink to &quot;Setting Up Your Identity&quot;">​</a></h3><p>Tell <strong>Git</strong> who you are for commit records. Replace <code>USERNAME</code> and <code>EMAIL</code> with your actual <strong>GitHub</strong> username and email:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;USERNAME&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;EMAIL&quot;</span></span></code></pre></div><h2 id="forking-the-repository" tabindex="-1">Forking the Repository <a class="header-anchor" href="#forking-the-repository" aria-label="Permalink to &quot;Forking the Repository&quot;">​</a></h2><p>When you fork a repository on <strong>GitHub</strong>, you create a fully independent copy under your own account. The original owner keeps their version; you now control yours and can set permissions, open issues, or adjust settings without affecting the source project.</p><p>On <strong>GitHub</strong>, fork the <code>class-cp115-repo</code> from this <a href="https://github.com/JSK-KML/CP115-Class-Repo" target="_blank" rel="noreferrer">link</a> by clicking the <code>Fork</code> button in <strong>GitHub</strong>. Proceed to the fork, without changing any default options.</p><p align="center"><img src="`+c+'" alt="drawing" width="400"></p><p>After you have done forking the repository, everything that you write is fully yours and only you can control it. So what is the difference between forking and simply copying?</p><p>The difference lies in the connection from the original copy. When you copy-paste something like a PDF documents, you have no connection to the original copy, meaning that if the original PDF changes, you will not know and you will not be notified.</p><p>For forking, there are still connections to the original repository, so if the original repository updates, you will be notified and you can update accordingly.</p><h2 id="cloning-your-repository" tabindex="-1">Cloning Your Repository <a class="header-anchor" href="#cloning-your-repository" aria-label="Permalink to &quot;Cloning Your Repository&quot;">​</a></h2><p>Now that you have done forking, the code is fully yours, but it only exists on <strong>GitHub</strong> web server. This is great, however, editing the code online, although feasible, is not a very smooth experience.</p><p>To solve this, we need to clone the repository into your computer so you can edit and run the code using your IDE, which in this class we have chosen <strong>VS Code</strong>.</p><p>In your <code>class-cp115-repo</code>, click <code>Code</code> and copy the link.</p><p align="center"><img src="'+d+'" alt="drawing" width="400"></p><p>Back in <strong>VS Code</strong>, choose <code>Source Control</code> from the sidebar and click <code>Clone repository</code> and paste the link that you have copied in the box when prompted. Then choose <code>Clone from URL</code>.</p><p align="center"><img src="'+g+'" alt="drawing" width="400"></p>',40)),n("h3",b,[e[0]||(e[0]=a("Cloning Using the Terminal ",-1)),i(t,{type:"tip",text:"Optional"}),e[1]||(e[1]=a()),e[2]||(e[2]=n("a",{class:"header-anchor",href:"#cloning-using-the-terminal","aria-label":'Permalink to "Cloning Using the Terminal <Badge type="tip" text="Optional" />"'},"​",-1))]),e[6]||(e[6]=o('<p>Instead of the graphical <code>Source Control</code> panel, you can also clone the repository using the <strong>terminal</strong>. This is the method most programmers use, and it is good to get familiar with it.</p><p>Open a terminal in <strong>VS Code</strong> by clicking <code>Terminal</code> and then <code>New Terminal</code>. A terminal will appear at the bottom of the window, already pointing at your workspace folder.</p><p>In the terminal, type the command below, replacing the link with the one you copied from the <code>Code</code> button on <strong>GitHub</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/YOUR-USERNAME/CP115-Class-Repo.git</span></span></code></pre></div><p>Press <code>Enter</code>, and <strong>Git</strong> will download a full copy of the repository into a new folder inside your workspace.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Both methods do the same thing. The <code>Source Control</code> panel runs the <code>git clone</code> command for you behind the scenes.</p></div><p>After finishing that, your local copy is ready to use. If you have completed the <strong>GitHub CLI</strong> setup earlier, your machine is already authenticated and you are good to go.</p><h2 id="commit-and-push" tabindex="-1">Commit and Push <a class="header-anchor" href="#commit-and-push" aria-label="Permalink to &quot;Commit and Push&quot;">​</a></h2><p>When you have finished cloning the repository, you will see that the folder and file on the computer is exactly like in the <strong>GitHub</strong> web. Now let&#39;s try to update our code. In <code>labs/lab01/exercise.py</code>, change the code from</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Hello, Lab 01&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>to</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Hello everyone, Lab 01&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>By changing the code, even if you add a space, <strong>VS Code</strong> will automatically detects the changes and will allow you to update the online repository that you have in <strong>GitHub</strong>.</p><p>On the sidebar, choose the <code>Source Control</code> and <strong>VS Code</strong> will automatically show you where the changes have been done. In the message box add appropriate message such as <code>Change the print in Lab 1</code> and click <code>Commit</code>.</p><p align="center"><img src="'+u+'" alt="drawing" width="400"></p><p>But what exactly is <code>Commit</code>? A commit records a snapshot of your changes in the local repository. Each commit carries a unique ID and a message explaining what changed, letting you roll back or review history at any point.</p><p><code>Push</code> is the <strong>Git</strong> action that copies your new commits from the local repository on your computer to the remote repository, which in our case is <code>cp115-class-repo</code>. Although the button shows <code>Sync</code>, behind the scene what it will do is <code>Push</code> and <code>Pull</code>.</p><p align="center"><img src="'+y+'" alt="drawing" width="400"></p><p>Now go back to your <strong>GitHub</strong> account in the browser. You should see that the repository has been updated with the commit message that you have added.</p><h2 id="syncing-fork" tabindex="-1">Syncing Fork <a class="header-anchor" href="#syncing-fork" aria-label="Permalink to &quot;Syncing Fork&quot;">​</a></h2><p>Once you fork a project, your copy starts aging the moment the original (“up-stream”) repo receives new commits. Syncing a fork is the act of pulling those new commits into your fork so it stays current—and so your pull requests don’t conflict with code that has already moved on.</p><p>To make sure your repository is up to date, go to you <strong>GitHub</strong> account and click <code>Sync Fork</code> and then choose <code>Update branch</code>.</p><p align="center"><img src="'+m+'" alt="drawing" width="400"></p><h2 id="recap" tabindex="-1">Recap <a class="header-anchor" href="#recap" aria-label="Permalink to &quot;Recap&quot;">​</a></h2><p>Congrats! You&#39;ve just navigated your first <strong>GitHub</strong> workflow. Here&#39;s a quick recap:</p><ul><li><p><code>Fork</code>: make a personal copy of any <strong>GitHub</strong> repository in your own account.</p></li><li><p><code>Clone</code>: bring that repository down to your computer, including its full history.</p></li><li><p><code>gh auth login</code>: authenticate your machine with <strong>GitHub</strong> so you can push and pull without entering credentials each time.</p></li><li><p><code>Commit</code>: record your local edits as a named snapshot with a clear message.</p></li><li><p><code>Push</code>: upload your committed snapshots from your machine to your <strong>GitHub</strong> repo.</p></li><li><p><code>Sync Fork</code>: pull in changes from the original project so your fork stays current.</p></li></ul>',26))])}const E=s(k,[["render",f]]);export{S as __pageData,E as default};
